from django.contrib import adminfrom django.urls import pathfrom django.shortcuts import render, redirectfrom django.contrib import messagesfrom .models import Test, Question, Answer, Resultdef add_questions_bulk(request, test_id):    test = Test.objects.get(id=test_id)        if request.method == 'POST':        questions_data = request.POST.get('questions_data', '')        lines = questions_data.strip().split('\n')                current_question = None        questions_added = 0        answers_added = 0                for line in lines:            line = line.strip()            if not line:                continue                        if line.startswith('Q: '):                question_text = line[3:].strip()                current_question = Question.objects.create(test=test, text=question_text)                questions_added += 1                        elif line.startswith('A: ') and current_question:                answer_text = line[3:].strip()                is_correct = False                if answer_text.endswith('*'):                    is_correct = True                    answer_text = answer_text[:-1].strip()                Answer.objects.create(                    question=current_question,                    text=answer_text,                    is_correct=is_correct                )                answers_added += 1                messages.success(            request,            f'✅ Добавлено {questions_added} вопросов и {answers_added} ответов!'        )        return redirect('admin:tests_question_changelist')        return render(        request,        'admin/tests/add_questions_bulk.html',        {'test': test}    )class TestAdmin(admin.ModelAdmin):    list_display = ('id', 'title', 'created_at')    search_fields = ('title',)        def get_urls(self):        urls = super().get_urls()        custom_urls = [            path(                '<int:test_id>/add-questions-bulk/',                add_questions_bulk,                name='add_questions_bulk'            ),        ]        return custom_urls + urlsclass QuestionAdmin(admin.ModelAdmin):    list_display = ('id', 'text', 'test')    list_filter = ('test',)    search_fields = ('text',)class AnswerAdmin(admin.ModelAdmin):    list_display = ('id', 'text', 'question', 'is_correct')    list_filter = ('question', 'is_correct')    search_fields = ('text',)class ResultAdmin(admin.ModelAdmin):    list_display = ('id', 'student', 'test', 'score', 'total', 'completed_at')    list_filter = ('test', 'completed_at')    search_fields = ('student__username', 'test__title')admin.site.register(Test, TestAdmin)admin.site.register(Question, QuestionAdmin)admin.site.register(Answer, AnswerAdmin)admin.site.register(Result, ResultAdmin)